## Plan
- Mock `fetch` to return controlled `Response` objects.
- Assert status passthrough for 503.
- Simulate `fetch` rejection for network errors.

```typescript
import { fetchStatus } from "./fetchStatus";

describe("fetchStatus", () => {
  const original = global.fetch;

  afterEach(() => {
    global.fetch = original;
  });

  it("returns HTTP status code", async () => {
    global.fetch = jest.fn().mockResolvedValue({ status: 503 } as Response);
    await expect(fetchStatus("https://api.example")).resolves.toBe(503);
    expect(global.fetch).toHaveBeenCalledWith("https://api.example/health");
  });

  it("propagates network failures", async () => {
    global.fetch = jest.fn().mockRejectedValue(new Error("boom"));
    await expect(fetchStatus("https://api.example")).rejects.toThrow("boom");
  });
});
```

## Notes
Requires Jest environment with `fetch` on `global`; adjust import path to match the project layout.
